import { Directive, ElementRef, Input } from '@angular/core';

@Directive({ selector: '[filePreview]' })
export class ImgVideoPreview {
  @Input() file: File;

  constructor(private el: ElementRef) {}

  async ngAfterViewInit() {
    if (this.file instanceof File) {
      const URL = this.getObjectURL(this.file);

      if (this.file.type.startsWith('image')) {
        this.setBgImage(URL, this.el.nativeElement);
      }

      if (this.file.type.startsWith('video')) {
        const { url, videoElement } = await this.drawImageByVideo(this.file);
        this.setBgImage(url, this.el.nativeElement);
        this.generateDurationSpan(videoElement, this.el.nativeElement);
      }
    }
  }

  convertTime(seconds: number) {
    return '';
  }

  generateDurationSpan(video: HTMLVideoElement, element: HTMLDivElement) {
    const durationEle = document.createElement('span');
    durationEle.innerText = this.convertTime(video.duration);
    durationEle.setAttribute(
      'style',
      'position:absolute; left:2px; bottom:2px; font-size:10px; color:#f2f2f2; font-weight:600'
    );
    element.setAttribute('style', 'position:relative');
    element.append(durationEle);
  }

  setBgImage(url: string, parentElement: HTMLElement) {
    const bgdiv = document.createElement('div');
    bgdiv.className = 'bgdiv';
    bgdiv.setAttribute(
      'style',
      `width:100%;
             height:0;
             padding-bottom:100%;
             background-image:url(${url});
             background-position: 50% 50%;
             background-repeat: no-repeat;
             background-size: cover;`
    );
    parentElement.append(bgdiv);
  }

  drawImageByVideo(file: File | { url: string }) {
    return new Promise<{ url: string; videoElement: HTMLVideoElement }>(
      (resolve, reject) => {
        let url = '';
        if (file instanceof File) {
          url = this.getObjectURL(file);
        } else {
          url = file.url;
        }
        const video = document.createElement('video');
        const snapImage = () => {
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          canvas
            .getContext('2d')
            .drawImage(video, 0, 0, canvas.width, canvas.height);
          const image = canvas.toDataURL('image/jpeg');
          resolve({
            url: image,
            videoElement: video,
          });
        };
        video.onloadeddata = function () {
          console.log('loadeddata');
          snapImage();
        };
        video.autoplay = true;
        video.oncanplay = function () {
          console.log('canplay');
        };
        video.setAttribute('crossOrigin', 'anonymous');
        video.preload = 'auto';
        video.src = url;
        video.muted = true;
      }
    );
  }

  getObjectURL(file) {
    let url = null;
    if (window?.URL) {
      // mozilla(firefox)
      url = window.URL.createObjectURL(file);
    } else if (window?.webkitURL) {
      // webkit or chrome
      url = window.webkitURL.createObjectURL(file);
    }
    return url;
  }
}
